// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract VotingSystem {
    struct Candidate {
        uint voteCount;
    }

    mapping(address => bool) public voters;
    mapping(uint => Candidate) public candidates;

    address public admin;
    bool public votingOpen;

    event CandidateRegistered(uint indexed candidateId);
    event VoteCast(address indexed voter, uint indexed candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingOpen = true;
    }

    function registerCandidate(uint candidateId) public {
        require(msg.sender == admin, "Only the admin can register a candidate");
        candidates[candidateId] = Candidate({voteCount: 0});
        emit CandidateRegistered(candidateId);
    }

    function vote(uint candidateId) public {
        require(voters[msg.sender] == false, "One vote per address");
        require(candidates[candidateId].voteCount > 0 || votingOpen, "Candidate does not exist or voting is closed");

        voters[msg.sender] = true;
        candidates[candidateId].voteCount += 1;

        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() public {
        require(msg.sender == admin, "Only the admin can end voting");
        votingOpen = false;

        emit VotingEnded();
    }

    function winner() public view returns (uint winningCandidate) {
        uint maxVotes = 0;

        for (uint i=1; i <= numberOfCandidates(); i++) {
            if (candidates[i].voteCount > maxVotes) {
                maxVotes = candidates[i].voteCount;
                winningCandidate = i;
            }
        }

        return winningCandidate;
    }

    function numberOfCandidates() public view returns (uint) {
        uint count = 0;

        for (uint i=1; i <= 9999; i++) {
            if (candidates[i].voteCount > 0) {
                count += 1;
            }
        }

        return count;
    }
}

