pragma solidity ^0.8.1;

contract VotingSystem {
    // Structure for storing candidate details
    struct Candidate {
        uint voteCount;
    }

    mapping(uint => Candidate) private candidates;
    mapping(address => bool) private voters;

    uint public totalCandidates = 0;
    address public admin;
    bool public votingOpen = false;

    event candidateRegistered (
        uint indexed _candidateId, 
        string _name
    );

    event voteCast (
         uint indexed _candidateId,
         address indexed voter
    );

    constructor() {
        admin = msg.sender;
    }

    // Function to register candidates
    function registerCandidate(string memory _name) public {
        require(msg.sender == admin, "Only the admin can register a candidate");
        uint id = totalCandidates;
        candidates[id] = Candidate({voteCount: 0});
        emit candidateRegistered(id, _name);
        totalCandidates++;
    }

    // Function to cast votes
    function vote(uint _candidateId) public {
        require(voters[msg.sender] == false, "One vote per address");
        require(_candidateId < totalCandidates, "Invalid candidate id");
        require(votingOpen, "Voting period is closed");

        voters[msg.sender] = true;
        candidates[_candidateId].voteCount += 1;

        emit voteCast(_candidateId, msg.sender);
    }

    // Function to end voting and return the winner
    function endVoting() public {
        require(msg.sender == admin, "Only the admin can end the voting");
        votingOpen = false;

        uint winningCandidateId = 0;
        for (uint i=1; i<totalCandidates; i++) {
            if (candidates[i].voteCount > candidates[winningCandidateId].voteCount){
                winningCandidateId = i;
            }
        }

        emit candidateRegistered(winningCandidateId, "Winner");
    }
}

