import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v4.3.2/contracts/access/Ownable.sol";

contract RoleBasedAccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");
    bytes32 public constant USER_ROLE = keccak256("USER_ROLE");

    mapping(bytes32 => mapping(address => bool)) private _roles;

    event RoleGranted(bytes32 role, address account, address sender);
    event RoleRevoked(bytes32 role, address account, address sender);

    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only admins can call this function");
        _;
    }

    constructor() {
        _roles[ADMIN_ROLE][msg.sender] = true;
    }

    function grantRole(bytes32 role, address account) public virtual onlyAdmin {
        require(account != address(0), "Account cannot be zero");
        if (_hasRole(role)) {
            _addRoleToMember(role, account);
        } else {
            _setupRole(role, account);
        }
        emit RoleGranted(role, account, msg.sender);
    }

    function revokeRole(bytes32 role, address account) public virtual onlyAdmin {
        require(account != address(0), "Account cannot be zero");
        if (_hasRole(role)) {
            _removeRoleFromMember(role, account);
        } else {
            revert("Account does not have the specified role");
        }
        emit RoleRevoked(role, account, msg.sender);
    }

    function renounceRole(bytes32 role) public virtual {
        require(hasRole(role, msg.sender), "Only members of this role can renounce it");
        revokeRole(role, msg.sender);
    }

    modifier onlyMemberOf(bytes32 role) {
        require(hasRole(role, msg.sender), "Caller must be a member of the specified role");
        _;
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role][account];
    }

    function addAdmin(address newAdmin) public onlyAdmin {
        require(newAdmin != address(0), "New admin cannot be zero");
        if (!hasRole(ADMIN_ROLE, newAdmin)) {
            grantRole(ADMIN_ROLE, newAdmin);
        }
    }

    function removeAdmin(address oldAdmin) public onlyAdmin {
        revokeRole(ADMIN_ROLE, oldAdmin);
    }

    function _addRoleToMember(bytes32 role, address account) internal {
        _roles[role][account] = true;
    }

    function _removeRoleFromMember(bytes32 role, address account) internal {
        _roles[role][account] = false;
    }

    function _setupRole(bytes32 role, address account) internal {
        _addRoleToMember(role, account);
    }

    function _hasRole(bytes32 role) internal view returns (bool) {
        return hasRole(role, msg.sender);
    }
}

