pragma solidity ^0.8.20;

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }
    enum Resolution { BuyerWins, SellerWins }

    struct ContractState {
        address buyer;
        address seller;
        address arbiter;
        uint256 amount;
        State state;
        bool delivered;
        Resolution resolution;
    }

    ContractState public contractState;

    event StateChanged(address indexed buyer, address indexed seller, State previousState, State newState);
    event PaymentReleased(address indexed buyer, address indexed seller, uint256 amount);
    event FundsRefunded(address indexed buyer, uint256 amount);
    event DisputeResolved(address indexed arbiter, Resolution outcome);

    modifier onlyBuyer() {
        require(msg.sender == contractState.buyer, "Not authorized");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == contractState.seller, "Not authorized");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == contractState.arbiter, "Not authorized");
        _;
    }

    constructor(
        address buyer,
        address seller,
        address arbiter
    ) payable {
        require(buyer != address(0), "Buyer address cannot be zero");
        require(seller != address(0), "Seller address cannot be zero");
        require(arbiter != address(0), "Arbiter address cannot be zero");
        require(buyer != seller, "Buyer and seller must be different addresses");
        require(buyer != arbiter, "Buyer and arbiter must be different addresses");
        require(seller != arbiter, "Seller and arbiter must be different addresses");

        contractState = ContractState({
            buyer: buyer,
            seller: seller,
            arbiter: arbiter,
            amount: msg.value,
            state: State.Created,
            delivered: false,
            resolution: Resolution.BuyerWins
        });

        emit StateChanged(buyer, seller, State.Created, State.Created);
    }

    function markDelivered() external onlySeller {
        require(contractState.state == State.Created, "Contract not in Created state");
        contractState.delivered = true;
        contractState.state = State.Delivered;

        emit StateChanged(
            contractState.buyer,
            contractState.seller,
            State.Created,
            State.Delivered
        );
    }

    function releasePayment() external onlyBuyer {
        require(contractState.state == State.Delivered, "Contract not in Delivered state");
        require(!contractState.delivered, "Item already delivered");

        payable(contractState.seller).transfer(contractState.amount);
        contractState.state = State.Released;

        emit PaymentReleased(
            contractState.buyer,
            contractState.seller,
            contractState.amount
        );
    }

    function dispute() external onlyBuyer {
        require(contractState.state == State.Delivered, "Contract not in Delivered state");
        contractState.state = State.Disputed;

        emit StateChanged(
            contractState.buyer,
            contractState.seller,
            State.Delivered,
            State.Disputed
        );
    }

    function resolveDispute(Resolution outcome) external onlyArbiter {
        require(contractState.state == State.Disputed, "Contract not in Disputed state");

        if (outcome == Resolution.BuyerWins) {
            payable(contractState.buyer).transfer(contractState.amount);
            contractState.state = State.Refunded;
        } else {
            require(!contractState.delivered, "Item already delivered");
            payable(contractState.seller).transfer(contractState.amount);
            contractState.state = State.Released;
        }

        contractState.resolution = outcome;

        emit DisputeResolved(
            contractState.arbiter,
            outcome
        );

        if (outcome == Resolution.BuyerWins) {
            emit FundsRefunded(contractState.buyer, contractState.amount);
        }
    }

    receive() external payable {
        revert("Direct Ether transfers not allowed");
    }

    function getContractState() external view returns (
        address,
        address,
        address,
        uint256,
        State,
        bool,
        Resolution
    ) {
        return (
            contractState.buyer,
            contractState.seller,
            contractState.arbiter,
            contractState.amount,
            contractState.state,
            contractState.delivered,
            contractState.resolution
        );
    }
}

