    event StateChanged(State indexed newState);
    event Deposit(address indexed buyer, uint256 amount);
    event Release(address indexed seller, uint256 amount);
    event Refund(address indexed buyer, uint256 amount);
    event Dispute(address indexed arbiter);

    address public buyer;
    address public seller;
    address public arbiter;
    State public state = State.Created;
    uint256 public depositAmount;

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Not the buyer");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Not the seller");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Not the arbiter");
        _;
    }

    modifier validAddress(address addr) {
        require(addr != address(0), "Invalid address");
        _;
    }

    constructor(address _buyer, address _seller, address _arbiter)
        validAddress(_buyer)
        validAddress(_seller)
        validAddress(_arbiter)
    {
        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        emit StateChanged(state);
    }

    receive() external payable onlyBuyer {
        require(msg.value == depositAmount, "Incorrect amount");
        state = State.Created;
        depositAmount = msg.value;
        emit Deposit(buyer, msg.value);
        emit StateChanged(state);
    }

    function markDelivered() external onlySeller {
        require(state == State.Created, "Invalid state");
        state = State.Delivered;
        emit StateChanged(state);
    }

    function releasePayment() external onlyBuyer {
        require(state == State.Delivered, "Invalid state");
        state = State.Released;
        payable(seller).transfer(depositAmount);
        emit Release(seller, depositAmount);
        emit StateChanged(state);
    }

    function refund() external onlyArbiter {
        require(state == State.Created || state == State.Disputed, "Invalid state");
        state = State.Refunded;
        payable(buyer).transfer(depositAmount);
        emit Refund(buyer, depositAmount);
        emit StateChanged(state);
    }

    function dispute() external onlyArbiter {
        require(state == State.Created, "Invalid state");
        state = State.Disputed;
        emit Dispute(arbiter);
        emit StateChanged(state);
    }
}

