    event VoteCast(address voter, uint candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingActive = true;
    }

    function registerCandidate(uint _candidateId, string memory _name) public {
        require(msg.sender == admin, "Only admin can register candidates");
        require(!candidateIds[_candidateId], "Candidate ID already exists");
        candidateIds[_candidateId] = true;
        candidates[_candidateId] = Candidate(_name, 0);
        if (_candidateId > maxCandidateId) {
            maxCandidateId = _candidateId;
        }
        emit CandidateRegistered(_candidateId, _name);
    }

    function vote(uint _candidateId) public {
        require(votingActive, "Voting has ended");
        require(!voters[msg.sender], "Voter already voted");
        require(candidateIds[_candidateId], "Candidate does not exist");
        require(msg.sender != admin, "Admin cannot vote");
        voters[msg.sender] = true;
        candidates[_candidateId].votes++;
