    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER");
    bytes32 public constant USER_ROLE = keccak256("USER");

    mapping(bytes32 => mapping(address => bool)) public roles;
    address public owner;

    event RoleGranted(bytes32 role, address account);
    event RoleRevoked(bytes32 role, address account);

    constructor() {
        owner = msg.sender;
        roles[ADMIN_ROLE][owner] = true;
        emit RoleGranted(ADMIN_ROLE, owner);
    }

    modifier onlyRole(bytes32 role) {
        require(hasRole(role, msg.sender), "RBAC: Caller does not have the required role");
        _;
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        require(account != address(0), "RBAC: Zero address");
        return roles[role][account];
    }

    function grantRole(bytes32 role, address account) public onlyRole(ADMIN_ROLE) {
        require(account != address(0), "RBAC: Zero address");
        roles[role][account] = true;
        emit RoleGranted(role, account);
    }

    function revokeRole(bytes32 role, address account) public onlyRole(ADMIN_ROLE) {
        require(account != address(0), "RBAC: Zero address");
        roles[role][account] = false;
        emit RoleRevoked(role, account);
    }

    function renounceRole(bytes32 role) public {
        require(hasRole(role, msg.sender), "RBAC: Caller does not have the role to renounce");
        roles[role][msg.sender] = false;
        emit RoleRevoked(role, msg.sender);
    }

    function adminFunction() public onlyRole(ADMIN_ROLE) {
        // Only admins can call this function
    }

    function managerFunction() public onlyRole(MANAGER_ROLE) {
        // Only managers can call this function
    }

    function userFunction() public onlyRole(USER_ROLE) {
        // Only users can call this function
    }
}

