pragma solidity ^0.8.20;

contract SimpleVoting {
    address public immutable owner;
    bool public votingActive = true;

    struct Candidate {
        string name;
        uint256 votes;
    }

    mapping(uint256 => Candidate) private candidates;
    mapping(address => bool) private hasVoted;
    uint256[] private candidateIds;

    event CandidateRegistered(uint256 indexed id, string name);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded();

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function registerCandidate(uint256 _id, string calldata _name) external onlyOwner {
        require(bytes(_name).length > 0, "Name required");
        require(candidates[_id].votes == 0 && bytes(candidates[_id].name).length == 0, "ID exists");
        candidates[_id] = Candidate({name: _name, votes: 0});
        candidateIds.push(_id);
        emit CandidateRegistered(_id, _name);
    }

    function vote(uint256 _candidateId) external {
        require(votingActive, "Voting ended");
        require(msg.sender != owner, "Owner cannot vote");
        require(!hasVoted[msg.sender], "Already voted");
        Candidate storage c = candidates[_candidateId];
        require(bytes(c.name).length > 0, "Candidate not found");
        c.votes += 1;
        hasVoted[msg.sender] = true;
        emit VoteCast(msg.sender, _candidateId);
    }

    function endVoting() external onlyOwner {
        require(votingActive, "Already ended");
        votingActive = false;
        emit VotingEnded();
    }

    function getWinner() external view returns (uint256 winnerId, string memory winnerName) {
        require(!votingActive, "Voting not finished");
        uint256 maxVotes = 0;
        for (uint256 i = 0; i < candidateIds.length; i++) {
            uint256 id = candidateIds[i];
            Candidate storage c = candidates[id];
            if (c.votes > maxVotes) {
                maxVotes = c.votes;
                winnerId = id;
                winnerName = c.name;
            }
        }
    }

    function getCandidate(uint256 _id) external view returns (string memory name, uint256 votes) {
        Candidate storage c = candidates[_id];
        require(bytes(c.name).length > 0, "Candidate not found");
        return (c.name, c.votes);
    }

    function hasAddressVoted(address _addr) external view returns (bool) {
        return hasVoted[_addr];
    }
}

pragma solidity ^0.8.20;

contract SimpleVoting {
    address public owner;
    bool public votingOpen = true;

    mapping(uint256 => string) public candidateNames;
    mapping(uint256 => bool) public candidateRegistered;
    uint256[] public candidateIds;
    mapping(uint256 => uint256) public voteCounts;
    mapping(address => bool) public hasVoted;

    uint256 public winnerId;
    uint256 public winnerVotes;

    event CandidateRegistered(uint256 indexed id, string name);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded(uint256 indexed winnerId, string winnerName);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not admin");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function registerCandidate(uint256 id, string calldata name) external onlyOwner {
        require(votingOpen, "Voting ended");
        require(!candidateRegistered[id], "ID already registered");
        candidateNames[id] = name;
        candidateRegistered[id] = true;
        candidateIds.push(id);
        emit CandidateRegistered(id, name);
    }

    function vote(uint256 id) external {
        require(votingOpen, "Voting ended");
        require(msg.sender != owner, "Admin cannot vote");
        require(candidateRegistered[id], "Candidate not registered");
        require(!hasVoted[msg.sender], "Already voted");

        hasVoted[msg.sender] = true;
        uint256 newCount = ++voteCounts[id];
        if (newCount > winnerVotes) {
            winnerVotes = newCount;
            winnerId = id;
        }
        emit VoteCast(msg.sender, id);
    }

    function endVoting() external onlyOwner {
        require(votingOpen, "Already ended");
        votingOpen = false;
        emit VotingEnded(winnerId, candidateNames[winnerId]);
    }

    function getWinner() external view returns (uint256 id, string memory name) {
        require(!votingOpen, "Voting not finished");
        return (winnerId, candidateNames[winnerId]);
    }

    function getVoteCount(uint256 id) external view returns (uint256) {
        require(candidateRegistered[id], "Candidate not registered");
        return voteCounts[id];
    }
}

pragma solidity ^0.8.20;

contract SimpleVoting {
    address public immutable admin;
    enum State { Open, Closed }
    State public votingState;

    struct Candidate {
        string name;
        uint256 voteCount;
        bool exists;
    }

    mapping(uint256 => Candidate) public candidates;
    uint256[] public candidateIds;
    mapping(address => bool) public hasVoted;

    event CandidateRegistered(uint256 indexed id, string name);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingState = State.Open;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier whenOpen() {
        require(votingState == State.Open, "Voting closed");
        _;
    }

    function registerCandidate(uint256 id, string calldata name) external onlyAdmin whenOpen {
        require(!candidates[id].exists, "Candidate exists");
        candidates[id] = Candidate({name: name, voteCount: 0, exists: true});
        candidateIds.push(id);
        emit CandidateRegistered(id, name);
    }

    function vote(uint256 candidateId) external whenOpen {
        require(msg.sender != admin, "Admin cannot vote");
        require(!hasVoted[msg.sender], "Already voted");
        Candidate storage cand = candidates[candidateId];
        require(cand.exists, "Candidate does not exist");
        cand.voteCount += 1;
        hasVoted[msg.sender] = true;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin whenOpen {
        votingState = State.Closed;
        emit VotingEnded();
    }

    function getWinner() external view returns (uint256 winnerId, string memory name) {
        require(votingState == State.Closed, "Voting not ended");
        uint256 maxVotes = 0;
        uint256 winId = 0;
        bool found = false;
        for (uint256 i = 0; i < candidateIds.length; i++) {
            uint256 id = candidateIds[i];
            Candidate storage cand = candidates[id];
            if (!found || cand.voteCount > maxVotes) {
                maxVotes = cand.voteCount;
                winId = id;
                found = true;
            }
        }
        if (found) {
            winnerId = winId;
            name = candidates[winId].name;
        } else {
            winnerId = 0;
            name = "";
        }
    }
}

