        txId = transactions.length;
        transactions.push(Transaction({target: target, value: value, data: data, executed: false}));
        emit Submission(txId, target, value, data);
    }

    function approveTransaction(uint256 txId) external onlyOwner {
        require(txId < transactions.length, "Tx not exist");
        Transaction storage txn = transactions[txId];
        require(!txn.executed, "Already executed");
        require(!approvals[txId][msg.sender], "Already approved");

        approvals[txId][msg.sender] = true;
        approvalCounts[txId]++;
        emit Approval(msg.sender, txId);
    }

    function executeTransaction(uint256 txId) external onlyOwner nonReentrant {
        require(txId < transactions.length, "Tx not exist");
        Transaction storage txn = transactions[txId];
        require(!txn.executed, "Already executed");
