contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }

    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    State public state;

    event StateChanged(State newState);
    event FundsReleased(address to, uint256 amount);
    event DisputeResolved(address winner);

    constructor(
        address _buyer,
        address _seller,
        address _arbiter
    ) payable {
        require(_buyer != address(0), "Buyer address cannot be zero");
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(_buyer != _seller, "Buyer and seller addresses must be different");
        require(_buyer != _arbiter, "Buyer and arbiter addresses must be different");
        require(_seller != _arbiter, "Seller and arbiter addresses must be different");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = msg.value;
        state = State.Created;

        emit StateChanged(state);
    }

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Only buyer can call this function");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Only seller can call this function");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Only arbiter can call this function");
        _;
    }

    modifier notDisputed() {
        require(state != State.Disputed, "Contract is in dispute");
        _;
    }

    function markDelivered() external onlySeller notDisputed {
        state = State.Delivered;
        emit StateChanged(state);
    }

    function releasePayment() external onlyBuyer notDisputed {
        require(state == State.Delivered, "Item has not been delivered");

        payable(seller).transfer(amount);

        state = State.Released;
        emit StateChanged(state);
        emit FundsReleased(seller, amount);
    }

    function dispute() external onlyBuyer notDisputed {
        require(state == State.Delivered, "Cannot dispute if item is not delivered");

        state = State.Disputed;
        emit StateChanged(state);
    }

    function resolveDispute(address winner) external onlyArbiter {
        require(state == State.Disputed, "Contract is not in dispute");
        require(winner != address(0), "Winner address cannot be zero");

        if (winner == buyer) {
            payable(buyer).transfer(amount);
        } else if (winner == seller) {
            payable(seller).transfer(amount);
        }

        state = State.Refunded;
        emit StateChanged(state);
        emit DisputeResolved(winner);
    }
}

